// --- Sparse-CBOR write (ADR-0042 driver path). ---

// Marshal writes the SoA buffer to w as the sparse-CBOR wire
// format produced through factsschema/dml_cbor. Thin wrapper
// around ErrorBuildEntities — the per-row chain lives there and
// works against any leeway-DML class that structurally satisfies
// ErrorEntityI.
func (c *ErrorColumns) Marshal(w io.Writer) (err error) {
	ent := errorPool.Get().(*cbdml.InEntityFacts)
	defer errorPool.Put(ent)
	ent.SetActiveSections(ErrorActiveSections)
	ent.Builder().SetActiveFields(ErrorActiveFields())
	err = ErrorBuildEntities(ent, c)
	if err != nil {
		return
	}
	var recs []*arrowrowcbor.Record
	recs, err = ent.TransferRecords(nil)
	if err != nil {
		err = eh.Errorf("errkind: transfer records: %w", err)
		return
	}
	rb := arrowrowcbor.JoinRecords(recs)
	_, err = w.Write(rb)
	if err != nil {
		err = eh.Errorf("errkind: marshal write: %w", err)
	}
	return
}

// --- Read path (ra-based). ---

// errorReader composes the readaccess helpers this kind needs.
// Constructed per Unmarshal call; released via defer.
type errorReader struct {
	EntityId        *ra.ReadAccessFactsPlainEntityIdAttributes
	EntityTimestamp *ra.ReadAccessFactsPlainEntityTimestampAttributes
	StringArray     *ra.ReadAccessFactsTaggedStringArray
	SymbolArray     *ra.ReadAccessFactsTaggedSymbolArray
	U32Array        *ra.ReadAccessFactsTaggedU32Array
	U64Array        *ra.ReadAccessFactsTaggedU64Array
	BlobArray       *ra.ReadAccessFactsTaggedBlobArray
}

func newErrorReader() *errorReader {
	return &errorReader{
		EntityId:        ra.NewReadAccessFactsPlainEntityIdAttributes(),
		EntityTimestamp: ra.NewReadAccessFactsPlainEntityTimestampAttributes(),
		StringArray:     ra.NewReadAccessFactsTaggedStringArray(),
		SymbolArray:     ra.NewReadAccessFactsTaggedSymbolArray(),
		U32Array:        ra.NewReadAccessFactsTaggedU32Array(),
		U64Array:        ra.NewReadAccessFactsTaggedU64Array(),
		BlobArray:       ra.NewReadAccessFactsTaggedBlobArray(),
	}
}

func (r *errorReader) loadFromRecord(rec arrow.Record) (err error) {
	err = r.EntityId.LoadFromRecord(rec)
	if err != nil {
		err = eh.Errorf("errkind: load EntityId: %w", err)
		return
	}
	err = r.EntityTimestamp.LoadFromRecord(rec)
	if err != nil {
		err = eh.Errorf("errkind: load EntityTimestamp: %w", err)
		return
	}
	err = r.StringArray.LoadFromRecord(rec)
	if err != nil {
		err = eh.Errorf("errkind: load StringArray: %w", err)
		return
	}
	err = r.SymbolArray.LoadFromRecord(rec)
	if err != nil {
		err = eh.Errorf("errkind: load SymbolArray: %w", err)
		return
	}
	err = r.U32Array.LoadFromRecord(rec)
	if err != nil {
		err = eh.Errorf("errkind: load U32Array: %w", err)
		return
	}
	err = r.U64Array.LoadFromRecord(rec)
	if err != nil {
		err = eh.Errorf("errkind: load U64Array: %w", err)
		return
	}
	err = r.BlobArray.LoadFromRecord(rec)
	if err != nil {
		err = eh.Errorf("errkind: load BlobArray: %w", err)
		return
	}
	return
}

func (r *errorReader) release() {
	if r == nil {
		return
	}
	if r.EntityId != nil {
		r.EntityId.Release()
	}
	if r.EntityTimestamp != nil {
		r.EntityTimestamp.Release()
	}
	if r.StringArray != nil {
		r.StringArray.Release()
	}
	if r.SymbolArray != nil {
		r.SymbolArray.Release()
	}
	if r.U32Array != nil {
		r.U32Array.Release()
	}
	if r.U64Array != nil {
		r.U64Array.Release()
	}
	if r.BlobArray != nil {
		r.BlobArray.Release()
	}
}

// Unmarshal appends one row to c per entity in rec, projecting
// the runtime.facts columns through factsschema/ra. Thin wrapper
// around ErrorFillFromArrow — the per-row decode lives there.
func (c *ErrorColumns) Unmarshal(rec arrow.Record) (err error) {
	r := newErrorReader()
	defer r.release()
	err = r.loadFromRecord(rec)
	if err != nil {
		return
	}
	n := r.EntityId.Len()
	err = ErrorFillFromArrow(
		c,
		n,
		r.EntityId.ValueId,
		r.EntityId.ValueNaturalKey,
		r.EntityTimestamp.ValueTs,
		r.StringArray.Attributes, r.StringArray.Memberships,
		r.SymbolArray.Attributes, r.SymbolArray.Memberships,
		r.U32Array.Attributes, r.U32Array.Memberships,
		r.U64Array.Attributes, r.U64Array.Memberships,
		r.BlobArray.Attributes, r.BlobArray.Memberships,
	)
	return
}

// --- buscodec.CodecI bridge. ---

// ErrorCodec is the buscodec.CodecI bridge for Error. Encodes one row
// through dml_cbor; decodes via cborarrow.Convert + ra-Unmarshal +
// Row(0). Auto-registered in init() so callers using buscodec.Encode
// / Decode route through here instead of the CBOR fallback.
type ErrorCodec struct{}

var _ buscodec.CodecI = (*ErrorCodec)(nil)

// errorBusCodec is the package-local singleton wired into buscodec.
var errorBusCodec = &ErrorCodec{}

func (inst *ErrorCodec) Name() (n string) {
	n = "error-sparse-cbor"
	return
}

func (inst *ErrorCodec) ContentType() (ct string) {
	ct = "application/x-runtime-facts+rb;kind=error"
	return
}

func (inst *ErrorCodec) Encode(v any) (b []byte, err error) {
	var row Error
	switch x := v.(type) {
	case Error:
		row = x
	case *Error:
		if x == nil {
			err = eh.Errorf("errkind: Encode nil *Error")
			return
		}
		row = *x
	default:
		err = eh.Errorf("errkind: Encode requires Error or *Error, got %T", v)
		return
	}
	cols := &ErrorColumns{}
	cols.Append(row)
	var buf bytes.Buffer
	err = cols.Marshal(&buf)
	if err != nil {
		err = eh.Errorf("errkind: Encode marshal: %w", err)
		return
	}
	b = buf.Bytes()
	return
}

func (inst *ErrorCodec) Decode(b []byte, v any) (err error) {
	target, ok := v.(*Error)
	if !ok {
		err = eh.Errorf("errkind: Decode requires *Error, got %T", v)
		return
	}
	var arrowBuf bytes.Buffer
	err = cborarrow.Convert(bytes.NewReader(b), &arrowBuf)
	if err != nil {
		err = eh.Errorf("errkind: Decode cborarrow: %w", err)
		return
	}
	rd, err := ipc.NewReader(&arrowBuf)
	if err != nil {
		err = eh.Errorf("errkind: Decode ipc reader: %w", err)
		return
	}
	defer rd.Release()
	if !rd.Next() {
		err = eh.Errorf("errkind: Decode expected one Arrow record, got none")
		return
	}
	rec := rd.RecordBatch()
	defer rec.Release()
	cols := &ErrorColumns{}
	err = cols.Unmarshal(rec)
	if err != nil {
		err = eh.Errorf("errkind: Decode unmarshal: %w", err)
		return
	}
	if cols.Len() != 1 {
		err = eb.Build().Int("got", cols.Len()).Errorf("errkind: Decode expected 1 row")
		return
	}
	*target = cols.Row(0)
	return
}
